  query getOnsiteMessaging($data: OnsiteMessagingInput!) {
    onsiteMessaging(data: $data){
      units {
        name
        canShow
        reason
        messages {
          name
          audience
          canShow
          reason
          selected
          outcome
          rank
        }
      }
      input {
        country
        continent
        debug
        deviceType
        name
        pageViewID
        url
        uri
        now
        referrer
        production
        language
      }
      responses {
        abra {
          error
          data {
            test
            variant
            integration
          }
        }
        meter {
          error
          data {
            meter
            viewed
            counted
            gateway
            granted
            section
            version
            abTests {
              name
              variation
            }
            loggedIn
            regiwall
            assetType
            countable
            threshold
            hitPaywall
            gatewayType
            grantReason
            hitRegiwall
            rulesVersion
            gatewayExempt
            gatewayEligible
            nytsNeedsRefresh
            gatewayTypeVariation
            peek
            region
            extendedAccess {
              signedEntitlements
              regiHash
              registrationTimestamp
            }
            extraData {
              key
              value
            }
          }
        }
        offerEligibility {
          error
          data {
            ...OfferEligibilityRules
          }
        }
        userState {
          error
          data {
            ...UserStateScopes
          }
        }
        subInfo {
          error
          data {
            subscriptionID
            products
            status
          }
        }
        algoEverything {
          error
          data {
            meta {
              surfaceNames
              units
            }
          }
        }
      }
      version
    }
  }
